import{_ as i,o as a,c as s,ae as t}from"./chunks/framework.BGHOrOyn.js";const u=JSON.parse('{"title":"MultiArch Builds","description":"","frontmatter":{},"headers":[],"relativePath":"software-engineering/containerisation/docker/multiarch-builds.md","filePath":"software-engineering/containerisation/docker/multiarch-builds.md"}'),o={name:"software-engineering/containerisation/docker/multiarch-builds.md"};function n(r,e,l,c,d,p){return a(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="multiarch-builds" tabindex="-1">MultiArch Builds <a class="header-anchor" href="#multiarch-builds" aria-label="Permalink to &quot;MultiArch Builds&quot;">​</a></h1><p><br><img src="https://chat.openai.com/_next/image?url=https%3A%2F%2Flh3.googleusercontent.com%2Fa%2FAGNmyxYYwN6bMkVgnW1hgjVNccFzedHnhA0HZ4ohGHp7EQ%3Ds96-c&amp;w=64&amp;q=75" alt="Devin Norgarb"></p><p><code>docker: Error response from daemon: image with reference multiarch/qemu-user-static was found but does not match the specified platform: wanted linux/arm64, actual: linux/amd64.</code></p><p>This error message suggests that you are trying to run a Docker image on a platform that is different from the one for which the image was built. The image you are trying to run is built for the <code>linux/arm64</code> platform, but the platform of your host system is <code>linux/amd64</code>.</p><p>To resolve this issue, you can use a tool called <code>qemu-user-static</code> to run the <code>linux/arm64</code> binary on your <code>linux/amd64</code> system. The <code>qemu-user-static</code> tool allows you to run binaries for foreign architectures on your host system by providing a lightweight emulation layer.</p><p>To use <code>qemu-user-static</code>, you need to follow these steps:</p><ol><li>Install the <code>qemu-user-static</code> package on your host system. On Ubuntu or Debian, you can do this with the following command:</li></ol><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sudo apt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-get</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> install qemu</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-static</span></span></code></pre></div><ol start="2"><li>Download the <code>multiarch/qemu-user-static</code> Docker image for the <code>linux/arm64</code> platform:</li></ol><div class="language-arduino vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">arduino</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>docker pull multiarch/qemu-user-static:register</span></span></code></pre></div><ol start="3"><li>Register the <code>qemu-user-static</code> binary as the default interpreter for the <code>linux/arm64</code> platform:</li></ol><div class="language-arduino vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">arduino</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>docker run --rm --privileged multiarch/qemu-user-static:register --reset</span></span></code></pre></div><ol start="4"><li>Try running your Docker image again:</li></ol><div class="language-arduino vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">arduino</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>docker run my_image</span></span></code></pre></div><p>This time, Docker should use the <code>qemu-user-static</code> binary to run the <code>linux/arm64</code> binary in your Docker image on your <code>linux/amd64</code> host system.</p><p>![](data:image/svg+xml,%3csvg%20xmlns=%27http://www.w3.org/2000/svg%27%20version=%271.1%27%20width=%2730%27%20height=%2730%27/%3e)<img src="https://chat.openai.com/_next/image?url=https%3A%2F%2Flh3.googleusercontent.com%2Fa%2FAGNmyxYYwN6bMkVgnW1hgjVNccFzedHnhA0HZ4ohGHp7EQ%3Ds96-c&amp;w=64&amp;q=75" alt="Devin Norgarb"></p><p><code>I am using macos</code></p><p>I apologize for the confusion. <code>binfmt-support</code> is a Linux package that provides support for registering binary formats with the kernel, and it&#39;s not available on macOS.</p><p>On macOS, you can use a tool called <code>docker-binfmt</code> to register support for foreign architectures. Here are the steps you can follow:</p><ol><li>Install <code>docker-binfmt</code> by running the following command in a terminal:</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker-binfmt</span></span></code></pre></div><ol start="2"><li>Enable <code>docker-binfmt</code> by running the following command:</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bsudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --privileged</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker/binfmt:a7996909642ee92942dcd6cff44b9b95f08dad64</span></span></code></pre></div><p>This command will enable support for various foreign architectures, including <code>linux/arm64</code>.</p><ol start="3"><li>Try running your Docker image again:</li></ol><div class="language-arduino vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">arduino</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>docker run my_image</span></span></code></pre></div><p>This time, Docker should be able to run the <code>linux/arm64</code> binary in your Docker image on your macOS host system.</p><p>I hope this helps!</p>',28)])])}const m=i(o,[["render",n]]);export{u as __pageData,m as default};
